parameters.jsCode:
// Combinar los 3 resultados y calcular NSE score
const allItems = $input.all();
const zoneData = $('💾 Extraer Coordenadas').first().json;

let clinicas_count = 0;
let colegios_privados_count = 0;
let negocios_premium_count = 0;
let avg_rating = 0;
let rating_sum = 0;
let rating_count = 0;

allItems.forEach((item, idx) => {
  const results = item.json.results || [];
  if (idx === 0) clinicas_count = results.length;
  else if (idx === 1) colegios_privados_count = results.length;
  else negocios_premium_count = results.length;

  results.forEach(r => {
    if (r.rating) { rating_sum += r.rating; rating_count++; }
  });
});

avg_rating = rating_count > 0 ? (rating_sum / rating_count).toFixed(1) : 0;

// Calcular NSE score (0-10)
const nse_score = Math.min(10, Math.round(
  (Math.min(clinicas_count, 5) / 5) * 3 +      // Clínicas: hasta 3 pts
  (Math.min(colegios_privados_count, 5) / 5) * 4 + // Colegios privados: hasta 4 pts
  (Math.min(negocios_premium_count, 10) / 10) * 3  // Negocios premium: hasta 3 pts
));

// Determinar NSE tier
let zona_nse = 'C+';
if (nse_score >= 8) zona_nse = 'A';
else if (nse_score >= 6) zona_nse = 'B+';
else if (nse_score >= 4) zona_nse = 'B';

// Calcular poder adquisitivo estimado ($USD/mes)
const poder_adq_map = { 'A': 7000, 'B+': 4500, 'B': 2500, 'C+': 1200 };
const ingreso_estimado = poder_adq_map[zona_nse];
const puede_pagar_350 = ingreso_estimado >= 2000;
const recomienda_becas = ingreso_estimado < 3000;

return [{ json: {
  zone_name: zoneData.zone_name,
  location: zoneData.location,
  // Indicadores
  clinicas_privadas: clinicas_count,
  colegios_privados: colegios_privados_count,
  negocios_premium: negocios_premium_count,
  avg_rating_zona: avg_rating,
  // Scores
  nse_score: nse_score,
  zona_nse: zona_nse,
  ingreso_estimado_usd: ingreso_estimado,
  poder_adquisitivo_score: nse_score,
  puede_pagar_pension_350: puede_pagar_350,
  recomendar_becas: recomienda_becas,
  // Segmentación EA
  segmento_ea: nse_score >= 6 ? 'Target Principal' : (nse_score >= 4 ? 'Target con Becas' : 'No Target'),
  promo_recomendada: ingreso_estimado >= 5000 ? 'Exclusividad + Metaverso' : (ingreso_estimado >= 3000 ? 'Innovación + Sin Matrícula' : 'Sin Matrícula + Becas'),
  analyzed_at: new Date().toISOString()
}}];

